import Timer from"../timer.js";describe("Timer",()=>{test("start schedules ticks",()=>{const e=new Timer;var t=jest.fn(),s=(e.on("tick",t),jest.fn().mockImplementationOnce(e=>(e(0),1)).mockImplementation(()=>1));global.requestAnimationFrame=s,e.start(),expect(t).toHaveBeenCalledTimes(2)}),test("stop unsubscribes",()=>{const e=new Timer,t=jest.fn();e.on("tick",t),e.start(),e.stop(),t.mockClear(),e.emit("tick"),expect(t).not.toHaveBeenCalled()})});